-- Addon namespace
local _, Private = ...
local L = Private.Libs.ACL

-- Global environment
local _G = _G

-- BuffReminders profile
function Private:Setup_BuffReminders()
	if not Private.IsAddOnLoaded('BuffReminders') then Private:Print('BuffReminders ' .. L["is not installed or enabled."]) return end

	-- Profile name
	local name = 'Luckyone'

	-- Profile string
	local importString = [[!BR_]]

	-- Profile import
	local BuffReminders = _G.BuffReminders
	BuffReminders:Import(importString, name)

	-- Not exported in string?
	BuffRemindersDB['profiles'][name] = BuffRemindersDB['profiles'][name] or {}
	BuffRemindersDB['profiles'][name]['buffTrackingMode'] = 'my_buffs'

	Private:Print(L["BuffReminders profile has been set."])
end
